{
  "name": "A Arte dos Incensos Artesanais",
  "description": "Página de vendas premium para o guia de incensos naturais, focada em alta conversão e estética artesanal."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
